#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_M 100
#define MAX_N 1000
#define MAX_T 5

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* node = (TreeNode*)malloc(sizeof(TreeNode));
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to perform DFS on the tree
void dfs(TreeNode* root, char* path, int* max_len) {
    if (root == NULL) return;
    if (root->left == NULL && root->right == NULL) {
        if (strlen(path) > *max_len) {
            *max_len = strlen(path);
        }
    } else {
        if (root->left != NULL) {
            strcat(path, "L");
            dfs(root->left, path, max_len);
            path[strlen(path) - 1] = '\0';
        }
        if (root->right != NULL) {
            strcat(path, "R");
            dfs(root->right, path, max_len);
            path[strlen(path) - 1] = '\0';
        }
    }
}

// Function to find the longest common prefix
int longestCommonPrefix(char** strs, int strsSize) {
    if (strsSize == 0) return 0;
    int min_len = strlen(strs[0]);
    for (int i = 1; i < strsSize; i++) {
        if (strlen(strs[i]) < min_len) {
            min_len = strlen(strs[i]);
        }
    }
    for (int i = 0; i < min_len; i++) {
        char c = strs[0][i];
        for (int j = 1; j < strsSize; j++) {
            if (strs[j][i] != c) return i;
        }
    }
    return min_len;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M;
        scanf("%d", &M);
        TreeNode** trees = (TreeNode**)malloc(M * sizeof(TreeNode*));
        for (int i = 0; i < M; i++) {
            int N;
            scanf("%d", &N);
            trees[i] = createTreeNode(1);
            for (int j = 0; j < N - 1; j++) {
                int u, v;
                char c;
                scanf("%d %c %d", &u, &c, &v);
                if (c == 'L') {
                    trees[i]->left = createTreeNode(v);
                } else {
                    trees[i]->right = createTreeNode(v);
                }
            }
        }
        int* max_lens = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < M; i++) {
            max_lens[i] = 0;
            char path[1000] = "";
            dfs(trees[i], path, &max_lens[i]);
        }
        for (int i = 1; i <= M; i++) {
            int max_len = 0;
            for (int j = 0; j < (1 << M); j++) {
                if (__builtin_popcount(j) == i) {
                    char** strs = (char**)malloc(i * sizeof(char*));
                    int k = 0;
                    for (int l = 0; l < M; l++) {
                        if ((j & (1 << l)) != 0) {
                            strs[k] = (char*)malloc(1000 * sizeof(char));
                            sprintf(strs[k], "%d", max_lens[l]);
                            k++;
                        }
                    }
                    int len = longestCommonPrefix(strs, i);
                    if (len > max_len) {
                        max_len = len;
                    }
                    for (int l = 0; l < i; l++) {
                        free(strs[l]);
                    }
                    free(strs);
                }
            }
            printf("%d ", max_len);
        }
        printf("\n");
        for (int i = 0; i < M; i++) {
            free(trees[i]);
        }
        free(trees);
        free(max_lens);
    }
    return 0;
}

