// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

// Define the structure for a tree node
struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
};

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* node = new TreeNode;
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to perform DFS on the tree
void dfs(TreeNode* root, string& path, int& max_len) {
    if (root == NULL) return;
    if (root->left == NULL && root->right == NULL) {
        if (path.length() > max_len) {
            max_len = path.length();
        }
    } else {
        if (root->left != NULL) {
            path += "L";
            dfs(root->left, path, max_len);
            path.pop_back();
        }
        if (root->right != NULL) {
            path += "R";
            dfs(root->right, path, max_len);
            path.pop_back();
        }
    }
}

// Function to find the longest common prefix
int longestCommonPrefix(vector<string>& strs) {
    if (strs.size() == 0) return 0;
    int min_len = strs[0].length();
    for (int i = 1; i < strs.size(); i++) {
        if (strs[i].length() < min_len) {
            min_len = strs[i].length();
        }
    }
    for (int i = 0; i < min_len; i++) {
        char c = strs[0][i];
        for (int j = 1; j < strs.size(); j++) {
            if (strs[j][i] != c) return i;
        }
    }
    return min_len;
}

