                cin >> u >> c >> v;
                if (c == 'L') {
                    trees[i]->left = createTreeNode(v);
                } else {
                    trees[i]->right = createTreeNode(v);
                }
            }
        }
        int* max_lens = new int[M];
        for (int i = 0; i < M; i++) {
            max_lens[i] = 0;
            string path = "";
            dfs(trees[i], path, max_lens[i]);
        }
        for (int i = 1; i <= M; i++) {
            int max_len = 0;
            for (int j = 0; j < (1 << M); j++) {
                if (__builtin_popcount(j) == i) {
                    vector<string> strs;
                    for (int l = 0; l < M; l++) {
                        if ((j & (1 << l)) != 0) {
                            strs.push_back(to_string(max_lens[l]));
                        }
